+import { Pattern } from './types/Pattern';
+import { MatchEach } from './types/MatchEach';
+import * as symbols from './internals/symbols';
+import { matchPattern } from './internals/helpers';
+import { NonExhaustiveError } from './errors';
+
+type Clause =
+  | { type: 'with'; patterns: Pattern<any>[]; predicate?: (value: any) => unknown; handler: (selection: unknown, value: any) => unknown }
+  | { type: 'when'; predicate: (value: any) => unknown; handler: (value: any) => unknown }
+  | { type: 'tap'; callback: (result: unknown) => void };
+
+/**
+ * `matchEach` creates a pattern matching expression that evaluates every
+ * matching clause and returns all of their results in declaration order.
+ */
+export function matchEach<const input, output = symbols.unset>(value: input): MatchEach<input, output>;
+export function matchEach<input, output = symbols.unset>(): MatchEach<input, output>;
+export function matchEach(value?: unknown): MatchEach<any, any> {
+  return new MatchEachExpression([], arguments.length > 0 ? value : undefined) as any;
+}
+
+class MatchEachExpression {
+  constructor(private clauses: readonly Clause[], private value?: unknown) {}
+
+  with(...args: any[]): MatchEachExpression {
+    const handler = args[args.length - 1];
+    const patterns: Pattern<any>[] = [args[0]];
+    let predicate: ((value: unknown) => unknown) | undefined;
+
+    if (args.length === 3 && typeof args[1] === 'function') predicate = args[1];
+    else if (args.length > 2) patterns.push(...args.slice(1, -1));
+
+    return this.add({ type: 'with', patterns, predicate, handler });
+  }
+
+  when(predicate: (value: unknown) => unknown, handler: (value: unknown) => unknown) {
+    return this.add({ type: 'when', predicate, handler });
+  }
+
+  tap(callback: (result: unknown) => void) {
+    return this.add({ type: 'tap', callback });
+  }
+
+  otherwise(handler: (value: unknown) => unknown): unknown[] {
+    const results = this.evaluate(this.value);
+    return results.length ? results : [handler(this.value)];
+  }
+
+  exhaustive(unexpectedValueHandler = defaultCatcher): unknown[] {
+    const results = this.evaluate(this.value);
+    return results.length ? results : [unexpectedValueHandler(this.value)];
+  }
+
+  run(): unknown[] {
+    return this.exhaustive();
+  }
+
+  returnType() { return this; }
+
+  narrow() { return this; }
+
+  toFunction() {
+    return (input: unknown) => {
+      const results = this.evaluate(input);
+      if (!results.length) defaultCatcher(input);
+      return results;
+    };
+  }
+
+  toPartialFunction() {
+    return (input: unknown) => {
+      const results = this.evaluate(input);
+      return results.length ? results : undefined;
+    };
+  }
+
+  toExhaustiveFunction() { return this.toFunction(); }
+
+  private add(clause: Clause) {
+    return new MatchEachExpression([...this.clauses, clause], this.value);
+  }
+
+  private evaluate(input: unknown): unknown[] {
+    const results: unknown[] = [];
+    for (const clause of this.clauses) {
+      if (clause.type === 'tap') {
+        results.forEach(clause.callback);
+        continue;
+      }
+      if (clause.type === 'when') {
+        if (clause.predicate(input)) results.push(clause.handler(input));
+        continue;
+      }
+
+      // Selections are deliberately local to this clause.
+      let hasSelections = false;
+      const selected: Record<string, unknown> = {};
+      const select = (key: string, selectedValue: unknown) => {
+        hasSelections = true;
+        selected[key] = selectedValue;
+      };
+      const matched = clause.patterns.some((pattern) => matchPattern(pattern, input, select));
+      if (!matched || (clause.predicate && !clause.predicate(input))) continue;
+      const selections = hasSelections
+        ? symbols.anonymousSelectKey in selected ? selected[symbols.anonymousSelectKey] : selected
+        : input;
+      results.push(clause.handler(selections, input));
+    }
+    return results;
+  }
